.darma-loader-uiverse-prism-pyramid {
  width: fit-content;
  height: fit-content;
  display: flex;
  align-items: center;
  justify-content: center;
  position: relative;
}

.darma-loader-uiverse-prism-pyramid__pyramid-loader {
  position: relative;
  width: 300px;
  height: 300px;
  display: block;
  transform-style: preserve-3d;
  transform: rotateX(-20deg);
}

.darma-loader-uiverse-prism-pyramid__wrapper {
position: relative;
width: 100%;
height: 100%;
transform-style: preserve-3d;
animation: darma-loader-uiverse-prism-pyramid-spin 4s linear infinite;
}

@keyframes darma-loader-uiverse-prism-pyramid-spin {
100% {
transform: rotateY(360deg);
}
}

.darma-loader-uiverse-prism-pyramid__pyramid-loader .darma-loader-uiverse-prism-pyramid__wrapper .darma-loader-uiverse-prism-pyramid__side {
width: 70px;
height: 70px;
/* you can choose any gradient or color you want */
/* background: radial-gradient( #2F2585 10%, #F028FD 70%, #2BDEAC 120%); */
position: absolute;
top: 0;
left: 0;
right: 0;
bottom: 0;
margin: auto;
transform-origin: center top;
clip-path: polygon(50% 0%, 0% 100%, 100% 100%);
}

.darma-loader-uiverse-prism-pyramid__pyramid-loader .darma-loader-uiverse-prism-pyramid__wrapper .darma-loader-uiverse-prism-pyramid__side1 {
transform: rotateZ(-30deg) rotateY(90deg);
background: conic-gradient( #2BDEAC, #F028FD, #D8CCE6, #2F2585);
}

.darma-loader-uiverse-prism-pyramid__pyramid-loader .darma-loader-uiverse-prism-pyramid__wrapper .darma-loader-uiverse-prism-pyramid__side2 {
transform: rotateZ(30deg) rotateY(90deg);
background: conic-gradient( #2F2585, #D8CCE6, #F028FD, #2BDEAC);
}

.darma-loader-uiverse-prism-pyramid__pyramid-loader .darma-loader-uiverse-prism-pyramid__wrapper .darma-loader-uiverse-prism-pyramid__side3 {
transform: rotateX(30deg);
background: conic-gradient( #2F2585, #D8CCE6, #F028FD, #2BDEAC);
}

.darma-loader-uiverse-prism-pyramid__pyramid-loader .darma-loader-uiverse-prism-pyramid__wrapper .darma-loader-uiverse-prism-pyramid__side4 {
transform: rotateX(-30deg);
background: conic-gradient( #2BDEAC, #F028FD, #D8CCE6, #2F2585);
}

.darma-loader-uiverse-prism-pyramid__pyramid-loader .darma-loader-uiverse-prism-pyramid__wrapper .darma-loader-uiverse-prism-pyramid__shadow {
width: 60px;
height: 60px;
background: #8B5AD5;
position: absolute;
top: 0;
left: 0;
right: 0;
bottom: 0;
margin: auto;
transform: rotateX(90deg) translateZ(-40px);
filter: blur(12px);
}

